import os
import subprocess
import json
import re
from google.cloud import storage

def validate_filename(filename):
    """Validate filename to prevent path traversal attacks"""
    if not filename:
        raise ValueError("Filename cannot be empty")
    
    # Check for path traversal attempts
    if '..' in filename or filename.startswith('/'):
        raise ValueError("Invalid filename: path traversal detected")
    
    # Only allow alphanumeric, dots, dashes, underscores
    if not re.match(r'^[a-zA-Z0-9._-]+$', filename):
        raise ValueError("Invalid filename: contains illegal characters")
    
    return filename

def validate_conversion_options(options):
    """Validate and sanitize ImageMagick conversion options"""
    if not isinstance(options, list):
        raise ValueError("Conversion options must be a list")
    
    # Whitelist of allowed ImageMagick operations
    allowed_operations = {
        '-resize', '-quality', '-format', '-rotate', '-crop',
        '-thumbnail', '-strip', '-colorspace', '-density',
        '-background', '-flatten', '-gravity', '-extent'
    }
    
    sanitized_options = []
    i = 0
    while i < len(options):
        option = str(options[i])
        
        # Check if option is in whitelist
        if option in allowed_operations:
            sanitized_options.append(option)
            
            # Add the value for options that require one
            if i + 1 < len(options) and not options[i + 1].startswith('-'):
                value = str(options[i + 1])
                
                # Validate value doesn't contain shell metacharacters
                if re.search(r'[;&|`$(){}[\]<>\\"\']', value):
                    raise ValueError(f"Invalid value for {option}: contains illegal characters")
                
                # Additional validation for specific options
                if option == '-format':
                    if value.lower() not in ['jpg', 'jpeg', 'png', 'gif', 'webp', 'bmp', 'tiff']:
                        raise ValueError(f"Unsupported output format: {value}")
                elif option == '-quality':
                    if not value.isdigit() or not (1 <= int(value) <= 100):
                        raise ValueError(f"Quality must be between 1 and 100")
                elif option in ['-resize', '-thumbnail', '-crop', '-extent']:
                    if not re.match(r'^[0-9x%!<>^@]+$', value):
                        raise ValueError(f"Invalid geometry value: {value}")
                elif option == '-rotate':
                    if not re.match(r'^-?[0-9]+$', value):
                        raise ValueError(f"Invalid rotation value: {value}")
                
                sanitized_options.append(value)
                i += 1
        else:
            raise ValueError(f"Operation not allowed: {option}")
        
        i += 1
    
    return sanitized_options

def convert_image(request):
    """Cloud Function triggered by Cloud Storage to convert images"""
    
    try:
        # Parse the Cloud Storage event
        event = request.get_json()
        
        if not event:
            return ('No event data provided', 400)
        
        # Extract bucket and file information
        bucket_name = event.get('bucket')
        file_name = event.get('name')
        
        if not bucket_name or not file_name:
            return ('Missing bucket or file name in event', 400)
        
        # Validate filename
        try:
            validated_filename = validate_filename(os.path.basename(file_name))
        except ValueError as e:
            return (f'Invalid filename: {str(e)}', 400)
        
        # Extract conversion options from metadata
        metadata = event.get('metadata', {})
        conversion_options_str = metadata.get('conversion_options', '[]')
        
        try:
            conversion_options = json.loads(conversion_options_str)
        except json.JSONDecodeError:
            return ('Invalid conversion_options format in metadata', 400)
        
        # Validate conversion options
        try:
            sanitized_options = validate_conversion_options(conversion_options)
        except ValueError as e:
            return (f'Invalid conversion options: {str(e)}', 400)
        
        # Get output format from options or default to jpg
        output_format = 'jpg'
        if '-format' in sanitized_options:
            format_index = sanitized_options.index('-format')
            if format_index + 1 < len(sanitized_options):
                output_format = sanitized_options[format_index + 1]
        
        # Initialize Cloud Storage client
        storage_client = storage.Client()
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        # Create temporary directory for processing
        temp_dir = '/tmp'
        input_path = os.path.join(temp_dir, f'input_{validated_filename}')
        
        # Generate output filename
        name_without_ext = os.path.splitext(validated_filename)[0]
        output_filename = f'{name_without_ext}_converted.{output_format}'
        output_path = os.path.join(temp_dir, output_filename)
        
        # Download the file
        blob.download_to_filename(input_path)
        
        # Construct ImageMagick convert command
        convert_command = ['convert', input_path] + sanitized_options + [output_path]
        
        # Execute conversion with timeout and resource limits
        try:
            result = subprocess.call(
                convert_command,
                timeout=300,  # 5 minute timeout
                env={
                    'PATH': os.environ.get('PATH', '/usr/bin:/bin'),
                    'MAGICK_MEMORY_LIMIT': '512MiB',
                    'MAGICK_MAP_LIMIT': '1GiB',
                    'MAGICK_DISK_LIMIT': '2GiB',
                    'MAGICK_TIME_LIMIT': '300'
                }
            )
            
            if result != 0:
                return (f'ImageMagick conversion failed with exit code {result}', 500)
                
        except subprocess.TimeoutExpired:
            return ('Image conversion timed out', 500)
        except Exception as e:
            return (f'Error during conversion: {str(e)}', 500)
        
        # Upload converted file back to Cloud Storage
        output_blob_name = f'converted/{output_filename}'
        output_blob = bucket.blob(output_blob_name)
        output_blob.upload_from_filename(output_path)
        
        # Clean up temporary files
        try:
            os.remove(input_path)
            os.remove(output_path)
        except Exception:
            pass
        
        return (json.dumps({
            'status': 'success',
            'input_file': file_name,
            'output_file': output_blob_name,
            'bucket': bucket_name
        }), 200)
        
    except Exception as e:
        return (f'Unexpected error: {str(e)}', 500)